import {
  generateFullColorPalette,
  generateIsolatedColor,
  generateIsolatedDarkColor,
  generateIsolatedDarkColorAntd,
  PresetColorsLarkLight,
} from '..';

describe('Snapshot testings', () => {
  it('generateFullColorPalette', () => {
    expect(generateFullColorPalette()).toMatchSnapshot();
  });

  it('generateIsolatedColor', () => {
    expect(generateIsolatedColor('#3370ff')).toMatchSnapshot();
  });

  it('generateIsolatedDarkColor', () => {
    expect(generateIsolatedDarkColor(PresetColorsLarkLight[0].colors)).toMatchSnapshot();
  });

  it('generateIsolatedDarkColorAntd', () => {
    expect(
      generateIsolatedDarkColorAntd(PresetColorsLarkLight[0].colors, {
        backgroundColor: '#191919',
      }),
    ).toMatchSnapshot();
  });
});
